--Q1: What is the total revenue generated by male vs. female customers?
SELECT gender, SUM(total_purchase_vnd) AS revenue
FROM customer
GROUP BY gender; 

--Q2: Which customers used a discount but still spent more than the average purchase amount?
SELECT customer_id, total_purchase_vnd
FROM customer
WHERE discount_applied = 'Yes' 
		AND total_purchase_vnd >= (SELECT AVG(total_purchase_vnd) FROM customer);

--Q3: Which are the top 5 products with the highest average review rating?
SELECT item_purchased, ROUND(AVG(review_rating::numeric), 2) AS avg_product_rating 
FROM customer
GROUP BY item_purchased
ORDER BY avg_product_rating DESC 
LIMIT 5;

--Q4: Compare the average purchase amount between Standard and Express shipping?
SELECT shipping_type, ROUND(AVG(total_purchase_vnd),2)
FROM customer
WHERE shipping_type = 'Standard' OR shipping_type = 'Express'
GROUP BY shipping_type;

--Q5: Do subscribed customers spend more? Compare average spend and total revenue between subscribers and non-subscribers.
SELECT subscription_member,
COUNT(customer_id) AS total_customers,
ROUND(AVG(total_purchase_vnd),2) AS avg_spend,
ROUND(SUM(total_purchase_vnd), 2) AS total_revenue
FROM customer
GROUP BY subscription_member
ORDER BY total_revenue, avg_spend DESC;

--Q6: Which 5 products have the highest percentage of purchases with discounts applied?
SELECT item_purchased,
ROUND(100 * SUM(CASE WHEN discount_applied = 'Yes' THEN 1 ELSE 0 END)/COUNT(*), 2) AS discount_rate
FROM customer
GROUP BY item_purchased
ORDER BY discount_rate DESC 
LIMIT 5;

--Q7: Segment customers into New, Returning and Loyal based on their total previous purchases, and show the count of each segment.
WITH customer_type AS (
SELECT customer_id, purchase_frequency_days,
CASE 
	WHEN purchase_frequency_days >= 365 THEN 'New'
	WHEN purchase_frequency_days BETWEEN 90 AND 364 THEN 'Returning'
	ELSE 'Loyal'
END AS customer_segment
FROM customer
)

SELECT customer_segment, COUNT(*) AS number_of_customers
FROM customer_type
GROUP BY customer_segment
ORDER BY number_of_customers DESC;

--Q8: What are the top 3 most purchased products within each category?
WITH item_counts AS (
SELECT category, item_purchased, 
COUNT(customer_id) AS total_orders,
ROW_NUMBER() OVER(PARTITION BY category ORDER BY COUNT(customer_id) DESC) AS item_rank
FROM customer
GROUP BY category, item_purchased
)

SELECT item_rank, category, item_purchased, total_orders
FROM item_counts
WHERE item_rank <= 3;

--Q9: What is the revenue contribution of each age group?
SELECT age_group, 
SUM(total_purchase_vnd) AS total_revenue
FROM customer
GROUP BY age_group
ORDER BY total_revenue DESC;

SELECT * 
FROM customer;